    30→
    31→/// Aggregated worker data for TUI display.
    32→#[derive(Debug, Default)]
    33→pub struct WorkerData {
    34→    /// All known workers by ID (from status files)
    35→    pub workers: HashMap<String, WorkerStatusFile>,
    36→    /// Counts by status
    37→    pub counts: WorkerCounts,
    38→    /// Last update timestamp
    39→    pub last_update: Option<std::time::Instant>,
    40→    /// Discovered tmux sessions (supplement to status files)
    41→    pub tmux_sessions: Option<DiscoveryResult>,
    42→    /// Last tmux discovery timestamp
    43→    pub tmux_last_update: Option<std::time::Instant>,
    44→    /// Health status per worker
    45→    pub health_status: HashMap<String, WorkerHealthStatus>,
    46→    /// Last health check timestamp
