    48→    /// Activity status per worker (idle/working/stuck)
    49→    pub activity_status: HashMap<String, WorkerActivity>,
    50→    /// Last activity check timestamp
    51→    pub activity_last_update: Option<std::time::Instant>,
    52→}
    53→
    54→impl WorkerData {
    55→    /// Create empty worker data (loading state).
    56→    pub fn new() -> Self {
    57→        Self::default()
    58→    }
    59→
    60→    /// Update from a StatusWatcher.
    61→    pub fn update_from_watcher(&mut self, watcher: &StatusWatcher) {
    62→        self.workers = watcher.workers().clone();
    63→        self.counts = watcher.worker_counts();
    64→        self.last_update = Some(std::time::Instant::now());
    65→    }
    66→
    67→    /// Update from tmux discovery result.
    68→    pub fn update_from_tmux(&mut self, result: DiscoveryResult) {
    69→        self.tmux_sessions = Some(result);
    70→        self.tmux_last_update = Some(std::time::Instant::now());
    71→    }
    72→
    73→    /// Update health status from health monitor.
    74→    pub fn update_health_status(&mut self, health: HashMap<String, WorkerHealthStatus>) {
    75→        self.health_status = health;
    76→        self.health_last_update = Some(std::time::Instant::now());
    77→    }
    78→
    79→    /// Get health status for a specific worker.
    80→    pub fn get_health(&self, worker_id: &str) -> Option<&WorkerHealthStatus> {
    81→        self.health_status.get(worker_id)
    82→    }
    83→
    84→    /// Count workers by health level.
    85→    pub fn health_counts(&self) -> (usize, usize, usize) {
    86→        let mut healthy = 0;
    87→        let mut degraded = 0;
    88→        let mut unhealthy = 0;
    89→
    90→        for health in self.health_status.values() {
    91→            match health.health_level() {
    92→                HealthLevel::Healthy => healthy += 1,
    93→                HealthLevel::Degraded => degraded += 1,
    94→                HealthLevel::Unhealthy => unhealthy += 1,
    95→            }
    96→        }
    97→
    98→        (healthy, degraded, unhealthy)
    99→    }
   100→
   101→    /// Update activity status from activity monitor.
   102→    pub fn update_activity_status(&mut self, activity: HashMap<String, WorkerActivity>) {
   103→        self.activity_status = activity;
   104→        self.activity_last_update = Some(std::time::Instant::now());
   105→    }
   106→
   107→    /// Get activity status for a specific worker.
   108→    pub fn get_activity(&self, worker_id: &str) -> Option<&WorkerActivity> {
   109→        self.activity_status.get(worker_id)
   110→    }
   111→
   112→    /// Get workers that are currently stuck (have task but no activity > 15 min).
   113→    pub fn stuck_workers(&self) -> Vec<&WorkerActivity> {
   114→        self.activity_status
   115→            .values()
   116→            .filter(|a| a.state == ActivityState::Stuck)
   117→            .collect()
   118→    }
   119→
   120→    /// Count workers by activity state (idle, working, stuck).
   121→    pub fn activity_counts(&self) -> (usize, usize, usize) {
   122→        let mut idle = 0;
   123→        let mut working = 0;
   124→        let mut stuck = 0;
   125→
   126→        for activity in self.activity_status.values() {
   127→            match activity.state {
   128→                ActivityState::Idle => idle += 1,
   129→                ActivityState::Working => working += 1,
   130→                ActivityState::Stuck | ActivityState::Unresponsive => stuck += 1,
   131→                ActivityState::Unknown => {}
   132→            }
   133→        }
   134→
   135→        (idle, working, stuck)
   136→    }
   137→
   138→    /// Check if data has been loaded.
   139→    pub fn is_loaded(&self) -> bool {
   140→        self.last_update.is_some()
   141→    }
   142→
   143→    /// Check if there are no workers (from status files).
   144→    pub fn is_empty(&self) -> bool {
