   166→
   167→    /// Get workers grouped by model.
   168→    pub fn workers_by_model(&self) -> HashMap<String, Vec<&WorkerStatusFile>> {
   169→        let mut by_model: HashMap<String, Vec<&WorkerStatusFile>> = HashMap::new();
   170→        for worker in self.workers.values() {
