   199→        }
   200→
   201→        let mut lines = Vec::new();
   202→
   203→        // If we have status file data, use it (more detailed)
   204→        if !self.is_empty() {
   205→            let c = &self.counts;
   206→            // Include paused count in total line if any workers are paused
   207→            let total_line = if paused_count > 0 {
