   426→            for worker in workers.iter().take(10) {
   427→                let time_str = if let Some(activity) = worker.last_activity {
   428→                    activity.format("%H:%M:%S").to_string()
   429→                } else if let Some(started) = worker.started_at {
   430→                    started.format("%H:%M:%S").to_string()
   431→                } else {
   432→                    now.format("%H:%M:%S").to_string()
   433→                };
   434→
   435→                let icon = match worker.status {
   436→                    WorkerStatus::Active => "⟳",
   437→                    WorkerStatus::Idle => "💤",
   438→                    WorkerStatus::Starting => "🔄",
   439→                    WorkerStatus::Failed => "❌",
   440→                    WorkerStatus::Stopped => "⏹",
   441→                    WorkerStatus::Error => "⚠",
   442→                    WorkerStatus::Paused => "⏸",
   443→                };
   444→
   445→                let message = match worker.status {
   446→                    WorkerStatus::Active => {
   447→                        if let Some(task) = &worker.current_task {
   448→                            format!("{} working on {}", worker.worker_id, task)
   449→                        } else {
   450→                            format!("{} is active", worker.worker_id)
   451→                        }
   452→                    }
   453→                    WorkerStatus::Idle => format!("{} idle", worker.worker_id),
   454→                    WorkerStatus::Starting => format!("Spawned {}", worker.worker_id),
   455→                    WorkerStatus::Failed => format!("{} failed", worker.worker_id),
   456→                    WorkerStatus::Stopped => format!("{} stopped", worker.worker_id),
   457→                    WorkerStatus::Error => format!("{} error", worker.worker_id),
   458→                    WorkerStatus::Paused => format!("{} paused", worker.worker_id),
   459→                };
   460→
   461→                lines.push(format!("{} {} {}", time_str, icon, message));
   462→            }
   463→        } else if let Some(ref tmux) = self.tmux_sessions {
   464→            // Fall back to tmux session activity
   465→            let mut workers: Vec<_> = tmux.workers.iter().collect();
   466→            workers.sort_by(|a, b| b.last_activity.cmp(&a.last_activity));
   467→
   468→            for worker in workers.iter().take(10) {
   469→                let time_str = worker.last_activity.format("%H:%M:%S").to_string();
   470→                let icon = if worker.is_attached { "⟳" } else { "💤" };
   471→                let status = if worker.is_attached {
   472→                    "attached"
   473→                } else {
   474→                    "detached"
   475→                };
   476→                let message = format!("{} {} ({})", worker.session_name, status, worker.age());
   477→
   478→                lines.push(format!("{} {} {}", time_str, icon, message));
   479→            }
   480→        }
   481→
   482→        if lines.is_empty() {
   483→            lines.push("No recent activity.".to_string());
   484→        }
   485→
   486→        lines.join("\n")
   487→    }
   488→}
