   490→/// Format a model identifier for display.
   491→fn format_model_name(model: &str) -> String {
   492→    // Common model name mappings
   493→    let lower = model.to_lowercase();
   494→    if lower.contains("glm-47") || lower.contains("glm47") || lower.contains("glm-4.7") {
   495→        "GLM-4.7".to_string()
   496→    } else if lower.contains("sonnet") {
   497→        "Sonnet".to_string()
   498→    } else if lower.contains("opus") {
   499→        "Opus".to_string()
   500→    } else if lower.contains("haiku") {
   501→        "Haiku".to_string()
   502→    } else if model.is_empty() {
   503→        "Unknown".to_string()
   504→    } else {
   505→        model.to_string()
   506→    }
   507→}
