   528→/// Truncate a string to a maximum length.
   529→fn truncate_string(s: &str, max_len: usize) -> String {
   530→    if s.len() <= max_len {
   531→        s.to_string()
   532→    } else if max_len > 2 {
   533→        format!("{}…", &s[..max_len - 1])
   534→    } else {
   535→        s[..max_len].to_string()
   536→    }
   537→}
