   897→    /// Build SubscriptionData from the tracker.
   898→    fn build_subscription_data(tracker: &SubscriptionTracker) -> SubscriptionData {
   899→        use crate::subscription_panel::{
   900→            ResetPeriod, SubscriptionAction, SubscriptionService, SubscriptionStatus,
   901→        };
   902→        use chrono::{Duration, Utc};
   903→        use tracing::info;
   904→
   905→        info!(
   906→            "Building subscription data, tracker has {} subscriptions",
   907→            tracker.len()
   908→        );
   909→
   910→        let mut data = SubscriptionData::new();
   911→
   912→        for summary in tracker.get_summaries() {
   913→            info!(
   914→                "Processing subscription: {} (usage: {}/{:?})",
   915→                summary.name, summary.quota_used, summary.quota_limit
   916→            );
   917→            // Map subscription name to service type
   918→            let service = if summary.name.to_lowercase().contains("anthropic")
   919→                || summary.name.to_lowercase().contains("claude")
   920→            {
   921→                SubscriptionService::ClaudePro
   922→            } else if summary.name.to_lowercase().contains("openai")
   923→                || summary.name.to_lowercase().contains("chatgpt")
   924→            {
   925→                SubscriptionService::ChatGPTPlus
   926→            } else if summary.name.to_lowercase().contains("cursor") {
   927→                SubscriptionService::CursorPro
   928→            } else {
   929→                SubscriptionService::DeepSeekAPI // Default fallback
   930→            };
   931→
   932→            let mut status = SubscriptionStatus::new(service);
   933→
   934→            // Set usage if we have a limit
   935→            if let Some(limit) = summary.quota_limit {
   936→                status = status.with_usage(summary.quota_used as u64, limit as u64, "tokens");
   937→            }
   938→
   939→            // Set billing period
   940→            let days_remaining = tracker.days_until_renewal(&summary.name).unwrap_or(30) as i64;
   941→            let reset_period = if days_remaining <= 1 {
   942→                ResetPeriod::Daily
   943→            } else if days_remaining <= 7 {
   944→                ResetPeriod::Weekly
   945→            } else {
   946→                ResetPeriod::Monthly
   947→            };
   948→            status = status.with_reset(Utc::now() + Duration::days(days_remaining), reset_period);
   949→
   950→            // Set active status
   951→            status = status.with_active(true);
   952→
   953→            // Map quota status to action
   954→            let action = match summary.status {
   955→                forge_cost::QuotaStatus::OnPace => SubscriptionAction::OnPace,
   956→                forge_cost::QuotaStatus::Accelerate => SubscriptionAction::Accelerate,
   957→                forge_cost::QuotaStatus::MaxOut => SubscriptionAction::MaxOut,
   958→                forge_cost::QuotaStatus::Depleted => SubscriptionAction::OverQuota,
   959→            };
   960→
   961→            // Check for alerts
   962→            let alert = tracker.get_alert(&summary.name);
   963→            if alert.is_alert() {
   964→                // Mark as critical/high usage in the status
   965→                if matches!(
   966→                    alert,
   967→                    forge_cost::SubscriptionAlert::Critical
   968→                        | forge_cost::SubscriptionAlert::Depleted
   969→                ) {
   970→                    // Override action to show urgency
   971→                    status.current_usage = status.limit.unwrap_or(100) - 1; // Show 99% used
   972→                }
   973→            }
   974→
   975→            data.subscriptions.push(status);
   976→        }
   977→
   978→        data.last_updated = Some(Utc::now());
   979→        data
   980→    }
