   982→    /// Poll for updates from the StatusWatcher, BeadManager, CostDatabase, and tmux discovery.
   983→    ///
   984→    /// This should be called regularly (e.g., in the event loop).
   985→    /// Returns true if any data changed.
   986→    pub fn poll_updates(&mut self) -> bool {
   987→        let mut changed = false;
   988→        let previous_worker_count = self.cached_worker_count;
   989→        let previous_bead_count = self.cached_bead_count;
   990→
   991→        // Poll status watcher
   992→        if let Some(ref mut watcher) = self.watcher {
   993→            // Drain all available events and check if any were received
   994→            let mut events_received = false;
   995→            while watcher.try_recv().is_some() {
   996→                events_received = true;
   997→            }
   998→
   999→            // Only update if events were received
  1000→            if events_received {
  1001→                // Clone current workers to detect changes (avoids borrow issues)
  1002→                let current_workers = watcher.workers().clone();
  1003→
  1004→                // Detect changes before updating
  1005→                for (worker_id, worker) in &current_workers {
  1006→                    let prev_status = self.prev_worker_statuses.get(worker_id);
  1007→
  1008→                    match prev_status {
  1009→                        None => {
  1010→                            // New worker discovered
  1011→                            self.activity_data.push(
  1012→                                ActivityEntry::new(
  1013→                                    ActivityEventType::WorkerSpawn,
  1014→                                    "Worker spawned",
  1015→                                )
  1016→                                .with_source(worker_id),
  1017→                            );
  1018→                        }
  1019→                        Some(prev) if *prev != worker.status => {
  1020→                            // Status transition
  1021→                            let message =
  1022→                                format!("Status changed: {:?} → {:?}", prev, worker.status);
  1023→                            let event_type = match worker.status {
  1024→                                WorkerStatus::Stopped => ActivityEventType::WorkerStop,
  1025→                                WorkerStatus::Failed | WorkerStatus::Error => {
  1026→                                    ActivityEventType::Error
  1027→                                }
  1028→                                _ => ActivityEventType::WorkerTransition,
  1029→                            };
  1030→                            self.activity_data.push(
  1031→                                ActivityEntry::new(event_type, message).with_source(worker_id),
  1032→                            );
  1033→
  1034→                            // Add task info if available
  1035→                            if let Some(ref task) = worker.current_task {
  1036→                                self.activity_data.push(
  1037→                                    ActivityEntry::new(
  1038→                                        ActivityEventType::TaskPickup,
  1039→                                        format!("Working on {}", task),
  1040→                                    )
  1041→                                    .with_source(worker_id),
  1042→                                );
  1043→                            }
  1044→                        }
  1045→                        _ => {}
  1046→                    }
  1047→                }
  1048→
  1049→                // Check for workers that were removed
  1050→                for worker_id in self.prev_worker_statuses.keys() {
  1051→                    if !current_workers.contains_key(worker_id) {
  1052→                        self.activity_data.push(
  1053→                            ActivityEntry::new(ActivityEventType::WorkerStop, "Worker stopped")
  1054→                                .with_source(worker_id),
  1055→                        );
  1056→                    }
  1057→                }
  1058→
  1059→                // Update previous statuses
  1060→                self.prev_worker_statuses = current_workers
  1061→                    .iter()
  1062→                    .map(|(k, v)| (k.clone(), v.status))
  1063→                    .collect();
  1064→
  1065→                // Now update worker data
  1066→                self.worker_data.update_from_watcher(watcher);
  1067→                changed = true;
  1068→            }
  1069→        }
  1070→
  1071→        // Poll bead manager for task queue updates
  1072→        let beads_changed = self.bead_manager.poll_updates();
  1073→        if beads_changed {
  1074→            // Add activity entries for bead changes
  1075→            self.detect_bead_changes();
  1076→            changed = true;
  1077→        }
  1078→
  1079→        // Periodically poll tmux discovery (less frequently)
  1080→        let should_poll_tmux = self.last_tmux_poll.map_or(true, |t| {
  1081→            t.elapsed().as_secs() >= TMUX_DISCOVERY_INTERVAL_SECS
  1082→        });
  1083→
  1084→        if should_poll_tmux {
  1085→            self.poll_tmux_discovery();
  1086→            self.last_tmux_poll = Some(std::time::Instant::now());
  1087→        }
  1088→
  1089→        // Periodically poll cost data
  1090→        let should_poll_costs = self
  1091→            .last_cost_poll
  1092→            .map_or(true, |t| t.elapsed().as_secs() >= COST_POLL_INTERVAL_SECS);
  1093→
  1094→        if should_poll_costs {
  1095→            self.poll_cost_data();
  1096→            self.last_cost_poll = Some(std::time::Instant::now());
  1097→        }
  1098→
  1099→        // Periodically poll metrics data (every 10 seconds)
  1100→        let should_poll_metrics = self.last_metrics_poll.map_or(true, |t| {
  1101→            t.elapsed().as_secs() >= METRICS_POLL_INTERVAL_SECS
  1102→        });
  1103→
  1104→        if should_poll_metrics {
  1105→            self.poll_metrics_data();
  1106→            self.last_metrics_poll = Some(std::time::Instant::now());
  1107→        }
  1108→
  1109→        // Poll log watcher for real-time API usage (more frequently - every 500ms)
  1110→        let should_poll_logs = self.last_log_poll.map_or(true, |t| {
  1111→            t.elapsed().as_millis() >= LOG_WATCHER_POLL_INTERVAL_MS as u128
  1112→        });
  1113→
  1114→        if should_poll_logs {
  1115→            self.poll_log_watcher();
  1116→            self.last_log_poll = Some(std::time::Instant::now());
  1117→        }
  1118→
  1119→        // Periodically poll subscription data (every 60 seconds)
  1120→        let should_poll_subscriptions = self.last_subscription_poll.map_or(true, |t| {
  1121→            t.elapsed().as_secs() >= SUBSCRIPTION_POLL_INTERVAL_SECS
  1122→        });
  1123→
  1124→        if should_poll_subscriptions {
  1125→            self.poll_subscription_data();
  1126→            self.last_subscription_poll = Some(std::time::Instant::now());
  1127→        }
  1128→
  1129→        // Periodically poll health monitoring (every 30 seconds)
  1130→        let should_poll_health = self
  1131→            .last_health_poll
  1132→            .map_or(true, |t| t.elapsed().as_secs() >= HEALTH_POLL_INTERVAL_SECS);
  1133→
  1134→        if should_poll_health {
  1135→            self.poll_health_monitor();
  1136→            self.last_health_poll = Some(std::time::Instant::now());
  1137→        }
  1138→
  1139→        // Periodically poll activity monitoring (every 15 seconds)
  1140→        let should_poll_activity = self
  1141→            .last_activity_poll
  1142→            .map_or(true, |t| t.elapsed().as_secs() >= ACTIVITY_POLL_INTERVAL_SECS);
  1143→
  1144→        if should_poll_activity {
  1145→            self.poll_activity_monitor();
  1146→            self.last_activity_poll = Some(std::time::Instant::now());
  1147→        }
  1148→
  1149→        // Update cached counts and mark dirty if changed
  1150→        self.cached_worker_count = self.worker_data.total_worker_count();
  1151→        self.cached_bead_count = self.bead_manager.total_bead_count();
  1152→
  1153→        if changed
  1154→            || previous_worker_count != self.cached_worker_count
  1155→            || previous_bead_count != self.cached_bead_count
  1156→        {
  1157→            self.dirty = true;
  1158→        }
  1159→
  1160→        self.dirty
  1161→    }
