  1251→    /// Poll health monitor for worker health status.
  1252→    fn poll_health_monitor(&mut self) {
  1253→        let Some(ref mut monitor) = self.health_monitor else {
  1254→            return;
  1255→        };
  1256→
  1257→        match monitor.check_all_health() {
  1258→            Ok(health_status) => {
  1259→                // Track previous health for comparison
  1260→                let prev_health = self.worker_data.health_status.clone();
  1261→
  1262→                // Check if any worker became unhealthy and add activity entries and alerts
  1263→                for (worker_id, health) in &health_status {
  1264→                    let prev_was_healthy = prev_health
  1265→                        .get(worker_id)
  1266→                        .map(|h| h.is_healthy)
  1267→                        .unwrap_or(true);
  1268→
  1269→                    // Log status transitions
  1270→                    if !health.is_healthy && prev_was_healthy {
  1271→                        // Worker just became unhealthy
  1272→                        let level = health.health_level();
  1273→                        let msg = match level {
  1274→                            forge_worker::health::HealthLevel::Degraded => {
  1275→                                format!(
  1276→                                    "Worker degraded: {} (score: {:.0}%)",
  1277→                                    health.primary_error.as_deref().unwrap_or("unknown"),
  1278→                                    health.health_score * 100.0
  1279→                                )
  1280→                            }
  1281→                            forge_worker::health::HealthLevel::Unhealthy => {
  1282→                                format!(
  1283→                                    "Worker unhealthy: {} (score: {:.0}%)",
  1284→                                    health.primary_error.as_deref().unwrap_or("unknown"),
  1285→                                    health.health_score * 100.0
  1286→                                )
  1287→                            }
  1288→                            forge_worker::health::HealthLevel::Healthy => {
  1289→                                "Worker healthy".to_string()
  1290→                            }
  1291→                        };
  1292→
  1293→                        self.activity_data.push(
  1294→                            ActivityEntry::new(ActivityEventType::Warning, msg.clone())
  1295→                                .with_source(worker_id),
  1296→                        );
  1297→
  1298→                        // Create one alert per worker based on the most critical failed check
  1299→                        // Priority: PID > Activity > Task > Memory > Response
  1300→                        let (alert_type, alert_msg) =
  1301→                            if health.failed_checks.contains(&HealthCheckType::PidExists) {
  1302→                                (AlertType::WorkerCrashed, health.primary_error.clone())
  1303→                            } else if health
  1304→                                .failed_checks
  1305→                                .contains(&HealthCheckType::ActivityFresh)
  1306→                            {
  1307→                                (AlertType::WorkerStale, health.primary_error.clone())
  1308→                            } else if health
  1309→                                .failed_checks
  1310→                                .contains(&HealthCheckType::TaskProgress)
  1311→                            {
  1312→                                (AlertType::TaskStuck, health.primary_error.clone())
  1313→                            } else if health.failed_checks.contains(&HealthCheckType::MemoryUsage) {
  1314→                                (AlertType::MemoryHigh, health.primary_error.clone())
  1315→                            } else if health
  1316→                                .failed_checks
  1317→                                .contains(&HealthCheckType::ResponseHealth)
  1318→                            {
  1319→                                (AlertType::WorkerUnresponsive, health.primary_error.clone())
  1320→                            } else {
  1321→                                // Fallback - shouldn't happen but just in case
  1322→                                (AlertType::WorkerCrashed, health.primary_error.clone())
  1323→                            };
  1324→
  1325→                        self.alert_manager
  1326→                            .raise(alert_type, worker_id.clone(), alert_msg);
  1327→
  1328→                        // Trigger notification (terminal bell) for the alert
  1329→                        let severity = alert_type.default_severity();
  1330→                        self.alert_notifier.notify(severity);
  1331→
  1332→                        // Add guidance for recovery
  1333→                        if !health.guidance.is_empty() {
  1334→                            for guidance in &health.guidance {
  1335→                                self.activity_data.push(
  1336→                                    ActivityEntry::new(
  1337→                                        ActivityEventType::Info,
  1338→                                        format!("Recovery: {}", guidance),
  1339→                                    )
  1340→                                    .with_source(worker_id),
  1341→                                );
  1342→                            }
  1343→                        }
  1344→                    }
  1345→
  1346→                    // Check for auto-restart trigger
  1347→                    if health.should_auto_restart {
  1348→                        let msg = format!(
  1349→                            "Auto-restart triggered after {} consecutive failures",
  1350→                            health.consecutive_failures
  1351→                        );
  1352→                        self.activity_data.push(
  1353→                            ActivityEntry::new(ActivityEventType::Warning, msg.clone())
  1354→                                .with_source(worker_id),
  1355→                        );
  1356→                        self.alert_manager.raise(
  1357→                            AlertType::AutoRestartTriggered,
  1358→                            worker_id.clone(),
  1359→                            Some(msg),
  1360→                        );
  1361→                        // Notify for auto-restart (warning severity)
  1362→                        self.alert_notifier.notify(AlertSeverity::Warning);
  1363→                    }
  1364→
  1365→                    // Check for recovery exhaustion
  1366→                    if health.recovery_exhausted && !health.is_healthy {
  1367→                        let msg = format!(
  1368→                            "Recovery exhausted ({} attempts) - manual intervention required",
  1369→                            health.recovery_attempts
  1370→                        );
  1371→                        self.activity_data.push(
  1372→                            ActivityEntry::new(ActivityEventType::Error, msg.clone())
  1373→                                .with_source(worker_id),
  1374→                        );
  1375→                        self.alert_manager.raise(
  1376→                            AlertType::RecoveryExhausted,
  1377→                            worker_id.clone(),
  1378→                            Some(msg),
  1379→                        );
  1380→                        // Notify for recovery exhausted (critical severity)
  1381→                        self.alert_notifier.notify(AlertSeverity::Critical);
  1382→                    }
  1383→
  1384→                    // Log when worker recovers - clear alerts
  1385→                    if health.is_healthy && !prev_was_healthy {
  1386→                        self.activity_data.push(
  1387→                            ActivityEntry::new(
  1388→                                ActivityEventType::Info,
  1389→                                "Worker recovered - all health checks passing".to_string(),
  1390→                            )
  1391→                            .with_source(worker_id),
  1392→                        );
  1393→                        // Resolve all alerts for this worker
  1394→                        self.alert_manager.resolve_all_for_worker(worker_id);
  1395→                    }
  1396→                }
  1397→
  1398→                let unhealthy_count = health_status.values().filter(|h| !h.is_healthy).count();
  1399→                let degraded_count = health_status
  1400→                    .values()
  1401→                    .filter(|h| {
  1402→                        matches!(
  1403→                            h.health_level(),
  1404→                            forge_worker::health::HealthLevel::Degraded
  1405→                        )
  1406→                    })
  1407→                    .count();
  1408→
  1409→                if unhealthy_count > 0 || degraded_count > 0 {
  1410→                    tracing::info!(
  1411→                        "Health check: {} unhealthy, {} degraded workers detected",
  1412→                        unhealthy_count,
  1413→                        degraded_count
  1414→                    );
  1415→                    self.dirty = true;
  1416→                }
  1417→
  1418→                // Update worker data with health status
  1419→                self.worker_data.update_health_status(health_status);
  1420→            }
  1421→            Err(e) => {
  1422→                tracing::warn!("Health check failed: {}", e);
  1423→                self.activity_data.push(ActivityEntry::new(
  1424→                    ActivityEventType::Error,
  1425→                    format!("Health check failed: {}", e),
  1426→                ));
  1427→            }
  1428→        }
  1429→    }
