  1431→    /// Poll activity monitor for idle/stuck worker detection.
  1432→    fn poll_activity_monitor(&mut self) {
  1433→        let mut activity_updates: HashMap<String, WorkerActivity> = HashMap::new();
  1434→        let mut stuck_count = 0;
  1435→
  1436→        // Check each worker's activity state
  1437→        for (worker_id, worker) in &self.worker_data.workers {
  1438→            let has_task = worker.current_task.is_some();
  1439→            let current_task = worker.current_task.clone();
  1440→            let last_activity = worker.last_activity;
  1441→            let worker_status = worker.status.to_string();
  1442→
  1443→            let activity = self.activity_monitor.get_activity(
  1444→                worker_id,
  1445→                has_task,
  1446→                current_task,
  1447→                last_activity,
  1448→                &worker_status,
  1449→            );
  1450→
  1451→            // Check for transition to stuck state
  1452→            let was_stuck = self
  1453→                .worker_data
  1454→                .get_activity(worker_id)
  1455→                .map(|a| a.state == ActivityState::Stuck)
  1456→                .unwrap_or(false);
  1457→
  1458→            if activity.state == ActivityState::Stuck && !was_stuck {
  1459→                // Worker just became stuck - raise alert and log activity
  1460→                let msg = format!(
  1461→                    "No activity for {} - may be stuck",
  1462→                    activity.activity_age_string()
  1463→                );
  1464→                self.activity_data.push(
  1465→                    ActivityEntry::new(ActivityEventType::Warning, msg.clone())
  1466→                        .with_source(worker_id),
  1467→                );
  1468→
  1469→                // Raise alert for stuck worker
  1470→                self.alert_manager.raise(
  1471→                    AlertType::TaskStuck,
  1472→                    worker_id.clone(),
  1473→                    Some(format!(
  1474→                        "Task {} stuck - no activity for {}",
  1475→                        activity.current_task.as_deref().unwrap_or("unknown"),
  1476→                        activity.activity_age_string()
  1477→                    )),
  1478→                );
  1479→
  1480→                // Trigger warning notification
  1481→                self.alert_notifier.notify(AlertSeverity::Warning);
  1482→                stuck_count += 1;
  1483→            } else if activity.state != ActivityState::Stuck && was_stuck {
  1484→                // Worker recovered from stuck state
  1485→                self.activity_data.push(
  1486→                    ActivityEntry::new(ActivityEventType::Info, "Worker activity resumed")
  1487→                        .with_source(worker_id),
  1488→                );
  1489→
  1490→                // Resolve stuck alert
  1491→                self.alert_manager.resolve_all_for_worker(worker_id);
  1492→            }
  1493→
  1494→            activity_updates.insert(worker_id.clone(), activity);
  1495→        }
  1496→
  1497→        // Update worker data with activity status
  1498→        if !activity_updates.is_empty() {
  1499→            self.worker_data.update_activity_status(activity_updates);
  1500→        }
  1501→
  1502→        if stuck_count > 0 {
  1503→            tracing::info!(
  1504→                "Activity check: {} stuck workers detected",
  1505→                stuck_count
  1506→            );
  1507→            self.dirty = true;
  1508→        }
  1509→    }
