  1511→    /// Poll subscription tracker for updates.
  1512→    fn poll_subscription_data(&mut self) {
  1513→        use chrono::{Duration, Utc};
  1514→        use tracing::info;
  1515→
  1516→        let Some(ref db) = self.cost_db else {
  1517→            // No database, just rebuild from tracker
  1518→            self.subscription_data = Self::build_subscription_data(&self.subscription_tracker);
  1519→            return;
  1520→        };
  1521→
  1522→        // 1. Check and auto-reset billing periods that have ended
  1523→        if let Ok(reset_count) = self.subscription_tracker.check_and_reset_billing(db) {
  1524→            if reset_count > 0 {
  1525→                info!("Reset {} subscription billing periods", reset_count);
  1526→                self.dirty = true;
  1527→            }
  1528→        }
  1529→
  1530→        // 2. Track recent API calls against subscriptions
  1531→        // Get API calls from the last polling interval (5 minutes)
  1532→        let since = Utc::now() - Duration::seconds(300); // 5 minutes
  1533→        if let Ok(recent_calls) = db.get_api_calls_since(since) {
  1534→            for call in recent_calls {
  1535→                // Find which subscription this model belongs to
  1536→                if let Some(ref sub_name) = self.subscription_tracker
  1537→                    .find_subscription_for_model(&call.model)
  1538→                {
  1539→                    // Track total tokens used
  1540→                    let total_tokens = call.total_tokens();
  1541→
  1542→                    // Record usage and update subscription quota
  1543→                    if let Err(e) = db.increment_subscription_usage(sub_name, total_tokens) {
  1544→                        tracing::warn!(
  1545→                            "Failed to increment subscription usage for {}: {}",
  1546→                            sub_name, e
  1547→                        );
  1548→                    } else {
  1549→                        // Update local tracker cache
  1550→                        self.subscription_tracker.increment_usage(sub_name, total_tokens);
  1551→
  1552→                        // Also record detailed usage event
  1553→                        use forge_cost::SubscriptionUsageRecord;
  1554→                        let sub_id = db.get_subscription_id(sub_name).ok().flatten();
  1555→                        if let Some(sid) = sub_id {
  1556→                            let record = SubscriptionUsageRecord::new(sid, total_tokens)
  1557→                                .with_worker(&call.worker_id)
  1558→                                .with_api_call(call.id.unwrap_or(0));
  1559→                            let _ = db.record_subscription_usage(&record);
  1560→                        }
  1561→                    }
  1562→                }
  1563→            }
  1564→        }
  1565→
  1566→        // 3. Reload subscriptions from database to get updated quota_used values
  1567→        if let Err(e) = self.subscription_tracker.load_from_database(db) {
  1568→            tracing::warn!("Failed to reload subscriptions from database: {}", e);
  1569→        }
  1570→
  1571→        // 4. Rebuild subscription data for display
  1572→        self.subscription_data = Self::build_subscription_data(&self.subscription_tracker);
  1573→
  1574→        // 5. Check for critical alerts
  1575→        if self.subscription_tracker.has_critical_alert() {
  1576→            self.dirty = true;
  1577→        }
  1578→    }
