  1580→    /// Poll cost database for updates.
  1581→    fn poll_cost_data(&mut self) {
  1582→        let Some(ref db) = self.cost_db else {
  1583→            self.cost_data = CostPanelData::with_error("Cost database not initialized");
  1584→            return;
  1585→        };
  1586→
  1587→        let query = CostQuery::new(db);
  1588→
  1589→        // Get today's costs
  1590→        match query.get_today_costs() {
  1591→            Ok(today) => {
  1592→                self.cost_data.set_today(today);
  1593→            }
  1594→            Err(e) => {
  1595→                self.cost_data.error = Some(format!("Failed to get today's costs: {}", e));
  1596→                return;
  1597→            }
  1598→        }
  1599→
  1600→        // Get this week's costs (last 7 days)
  1601→        match query.get_weekly_costs() {
  1602→            Ok(week) => {
  1603→                self.cost_data.set_week(week);
  1604→            }
  1605→            Err(_) => {
  1606→                // Weekly cost failure is non-critical
  1607→            }
  1608→        }
  1609→
  1610→        // Get current month's costs
  1611→        match query.get_current_month_costs() {
  1612→            Ok(monthly) => {
  1613→                // Convert to model costs for display
  1614→                let model_costs: Vec<forge_cost::ModelCost> = monthly
  1615→                    .by_model
  1616→                    .iter()
  1617→                    .map(|b| forge_cost::ModelCost {
  1618→                        model: b.model.clone(),
  1619→                        total_cost_usd: b.total_cost_usd,
  1620→                        call_count: b.call_count,
  1621→                        avg_cost_per_call: if b.call_count > 0 {
  1622→                            b.total_cost_usd / b.call_count as f64
  1623→                        } else {
  1624→                            0.0
  1625→                        },
  1626→                        total_tokens: b.input_tokens
  1627→                            + b.output_tokens
  1628→                            + b.cache_creation_tokens
  1629→                            + b.cache_read_tokens,
  1630→                    })
  1631→                    .collect();
  1632→
  1633→                self.cost_data
  1634→                    .set_monthly(monthly.total_cost_usd, model_costs);
  1635→
  1636→                // Build daily trend from monthly data
  1637→                let trend: Vec<(chrono::NaiveDate, f64)> = monthly
  1638→                    .by_day
  1639→                    .iter()
  1640→                    .map(|d| (d.date, d.total_cost_usd))
  1641→                    .collect();
  1642→                self.cost_data.set_daily_trend(trend);
  1643→            }
  1644→            Err(e) => {
  1645→                self.cost_data.error = Some(format!("Failed to get monthly costs: {}", e));
  1646→            }
  1647→        }
  1648→
  1649→        // Get projected costs
  1650→        match query.get_projected_costs(None) {
  1651→            Ok(projected) => {
  1652→                self.cost_data.set_projected(projected);
  1653→            }
  1654→            Err(_) => {
  1655→                // Projection failure is non-critical
  1656→            }
  1657→        }
  1658→
  1659→        // Get optimization data using CostOptimizer
  1660→        let optimizer = forge_cost::CostOptimizer::new(db, forge_cost::OptimizerConfig::default());
  1661→        match optimizer.generate_report() {
  1662→            Ok(report) => {
  1663→                self.cost_data.set_recommendations(report.recommendations);
  1664→                self.cost_data.set_savings_achieved(report.savings_achieved);
  1665→                self.cost_data
  1666→                    .set_subscription_utilization(report.subscription_utilization);
  1667→            }
  1668→            Err(_) => {
  1669→                // Optimization failure is non-critical
  1670→            }
  1671→        }
  1672→
  1673→        // Set default budget config (can be customized later)
  1674→        self.cost_data.set_budget(BudgetConfig::default());
  1675→
  1676→        // Get worker cost breakdown (top 10 workers)
  1677→        match query.get_today_worker_costs(10) {
  1678→            Ok(mut workers) => {
  1679→                // Calculate session total and mark expensive workers
  1680→                let session_total: f64 = workers.iter().map(|w| w.total_cost_usd).sum();
  1681→
  1682→                // Set expensive threshold to 10% of session total or $1, whichever is higher
  1683→                let threshold = (session_total * 0.1).max(1.0);
  1684→                for worker in &mut workers {
  1685→                    worker.is_expensive = worker.total_cost_usd >= threshold;
  1686→                }
  1687→
  1688→                self.cost_data.set_worker_costs(workers);
  1689→                self.cost_data.set_session_total(session_total);
  1690→                self.cost_data.set_expensive_threshold(threshold);
  1691→            }
  1692→            Err(_) => {
  1693→                // Worker cost failure is non-critical
  1694→            }
  1695→        }
  1696→    }
