  1698→    /// Poll tmux for worker sessions.
  1699→    fn poll_tmux_discovery(&mut self) {
  1700→        if let Some(ref runtime) = self.runtime {
  1701→            // Run tmux discovery asynchronously but block briefly for result
  1702→            match runtime.block_on(async {
  1703→                tokio::time::timeout(
  1704→                    std::time::Duration::from_millis(500),
  1705→                    forge_worker::discover_workers(),
  1706→                )
  1707→                .await
  1708→            }) {
  1709→                Ok(Ok(result)) => {
  1710→                    self.worker_data.update_from_tmux(result);
  1711→                }
  1712→                Ok(Err(_)) | Err(_) => {
  1713→                    // Discovery failed or timed out - that's okay, status files are primary
  1714→                }
  1715→            }
  1716→        }
  1717→    }
