  1824→    /// Poll log watcher for real-time API usage updates.
  1825→    fn poll_log_watcher(&mut self) {
  1826→        // Collect calls to persist to database
  1827→        let mut calls_to_persist: Vec<forge_cost::ApiCall> = Vec::new();
  1828→
  1829→        // Process events from log watcher channel
  1830→        if let Some(ref rx) = self.log_rx {
  1831→            while let Ok(event) = rx.try_recv() {
  1832→                match event {
  1833→                    LogWatcherEvent::ApiCallParsed { call } => {
  1834→                        // Update real-time metrics
  1835→                        self.realtime_metrics.record_call(&call);
  1836→
  1837→                        // Collect for database persistence
  1838→                        calls_to_persist.push(call.clone());
  1839→
  1840→                        // Add activity entry for API call
  1841→                        let cost_str = if call.cost_usd >= 1.0 {
  1842→                            format!("${:.2}", call.cost_usd)
  1843→                        } else if call.cost_usd >= 0.01 {
  1844→                            format!("${:.3}", call.cost_usd)
  1845→                        } else {
  1846→                            format!("${:.4}", call.cost_usd)
  1847→                        };
  1848→                        let msg = format!(
  1849→                            "{} API call - {} in, {} out ({})",
  1850→                            call.model, call.input_tokens, call.output_tokens, cost_str
  1851→                        );
  1852→                        self.activity_data.push(
  1853→                            ActivityEntry::new(ActivityEventType::ApiCall, msg)
  1854→                                .with_source(&call.worker_id),
  1855→                        );
  1856→
  1857→                        // The real-time metrics are now available for panels
  1858→                        // via self.realtime_metrics
  1859→                        self.dirty = true;
  1860→                    }
  1861→                    LogWatcherEvent::FileDiscovered { path, worker_id } => {
  1862→                        tracing::debug!("Log file discovered: {:?} for worker {}", path, worker_id);
  1863→                    }
  1864→                    LogWatcherEvent::FileRotated { path, worker_id } => {
  1865→                        tracing::debug!("Log file rotated: {:?} for worker {}", path, worker_id);
  1866→                    }
  1867→                    LogWatcherEvent::Error { message } => {
  1868→                        tracing::warn!("Log watcher error: {}", message);
  1869→                    }
  1870→                }
  1871→            }
  1872→        }
  1873→
  1874→        // Also poll the log watcher directly for any new content
  1875→        if let Some(ref mut watcher) = self.log_watcher {
  1876→            let events = watcher.poll();
  1877→            for event in events {
  1878→                if let LogWatcherEvent::ApiCallParsed { call } = event {
  1879→                    self.realtime_metrics.record_call(&call);
  1880→                    calls_to_persist.push(call);
  1881→                    self.dirty = true;
  1882→                }
  1883→            }
  1884→        }
  1885→
  1886→        // Persist collected API calls to the database for historical tracking
  1887→        if !calls_to_persist.is_empty() {
  1888→            if let Some(ref db) = self.cost_db {
  1889→                if let Err(e) = db.insert_api_calls(&calls_to_persist) {
  1890→                    tracing::warn!(
  1891→                        "Failed to persist {} API calls to database: {}",
  1892→                        calls_to_persist.len(),
  1893→                        e
  1894→                    );
  1895→                } else {
  1896→                    tracing::debug!("Persisted {} API calls to database", calls_to_persist.len());
  1897→                }
  1898→            }
  1899→        }
  1900→
  1901→        // Propagate realtime metrics to cost_data and metrics_data for panel display
  1902→        if self.realtime_metrics.has_data() {
  1903→            self.cost_data.set_realtime(self.realtime_metrics.clone());
  1904→            self.metrics_data
  1905→                .set_realtime(self.realtime_metrics.clone());
  1906→        }
  1907→    }
